import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { ResponsiveChartContainer, LinePlot, ChartsXAxis, ChartsYAxis, ChartsClipPath } from '@mui/x-charts';
import response from './response.json';

interface DeviceData {
  totalConnected: number;
  inactive: number;
  active: number;
}

interface EnergyUsage {
  currentUsage: number;
  unit: string;
  trend: number[];
}

interface RoomTemperature {
  room: string;
  temperature: number;
}

interface WidgetData {
  devices: DeviceData;
  energyUsage: EnergyUsage;
  roomTemperatures: RoomTemperature[];
}

export default function Widget() {
  const data = response.data as WidgetData;
  const clipPathId = useId();

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 500, bgcolor: '#1E293B' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="body2" color="text.secondary" sx={{ color: '#94A3B8' }}>
              Energy Usage
            </Typography>
            <Typography variant="h4" fontWeight={600} sx={{ color: '#F8FAFC', mb: 1 }}>
              {data.energyUsage.currentUsage} {data.energyUsage.unit}
            </Typography>
          </Box>

          <Box sx={{ width: '100%', height: 200 }}>
            <ResponsiveChartContainer
              series={[
                {
                  type: 'line',
                  data: data.energyUsage.trend,
                  color: '#3B82F6',
                  label: 'Trend',
                  curve: 'linear',
                },
              ]}
              xAxis={[
                {
                  scaleType: 'linear',
                  data: data.energyUsage.trend.map((_, index) => index),
                  id: 'time',
                },
              ]}
              yAxis={[{ id: 'usage' }]}
            >
              <g clipPath={`url(#${clipPathId})`}>
                <LinePlot />
              </g>
              <ChartsXAxis
                axisId="time"
                tickLabelStyle={{ fontSize: 10, fill: '#94A3B8' }}
              />
              <ChartsYAxis
                axisId="usage"
                tickLabelStyle={{ fontSize: 10, fill: '#94A3B8' }}
              />
              <ChartsClipPath id={clipPathId} />
            </ResponsiveChartContainer>
          </Box>

          <Stack direction="row" spacing={1.5}>
            {data.roomTemperatures.map((roomTemp) => (
              <Box key={roomTemp.room}>
                <Typography variant="caption" color="text.secondary">
                  {roomTemp.room}
                </Typography>
                <Typography variant="body2" fontWeight={500} sx={{ color: '#F8FAFC' }}>
                  {roomTemp.temperature}°F
                </Typography>
              </Box>
            ))}
          </Stack>
        </Stack>
      </CardContent>
    </Card>
  );
}
